import numpy as np
import time
import torch
import numba
import sys

# Methods
def np_outer(v1, v2):
    return np.outer(v1, v2)

def np_einsum(v1, v2):
    return np.einsum('i,j->ij', v1, v2)

def np_multiply_outer(v1, v2):
    return np.multiply.outer(v1, v2)

def np_broadcast(v1, v2):
    return v1[:, None] * v2[None, :]

# Torch on CPU
def torch_outer(v1, v2):
    t1 = torch.from_numpy(v1)
    t2 = torch.from_numpy(v2)
    return torch.outer(t1, t2).numpy()

# Numba JIT
@numba.njit(parallel=True)
def numba_outer(v1, v2):
    n = len(v1)
    out = np.empty((n, n), dtype=np.float64)
    for i in numba.prange(n):
        for j in range(n):
            out[i, j] = v1[i] * v2[j]
    return out

# Warm up numba (compile once)
numba_outer(np.array([1.0]), np.array([2.0]))

# Test with different sizes
sizes = [10, 100, 1000, 5000, 10000]
for n in sizes:
    v1 = np.random.randn(n)
    v2 = np.random.randn(n)
    methods = {
        'np.outer': np_outer,
        'np.einsum': np_einsum,
        'np.multiply.outer': np_multiply_outer,
        'np.broadcast': np_broadcast,
        'torch.outer': torch_outer,
        'numba': numba_outer,
    }
    print(f'\nSize {n}:')
    for name, func in methods.items():
        # Warmup for torch (maybe)
        if name == 'torch.outer':
            _ = func(v1, v2)
        start = time.perf_counter()
        for _ in range(10):
            result = func(v1, v2)
        elapsed = (time.perf_counter() - start) / 10
        # Check correctness against np.outer
        ref = np.outer(v1, v2)
        diff = np.max(np.abs(result - ref))
        if diff > 1e-12:
            print(f'{name:20s}: max diff {diff:.2e} -- WARNING')
        else:
            print(f'{name:20s}: {elapsed*1000:.3f} ms')
