import numpy as np
import time
import statistics

# Methods
def np_outer(v1, v2):
    return np.outer(v1, v2)

def np_einsum(v1, v2):
    return np.einsum('i,j->ij', v1, v2)

def np_broadcast(v1, v2):
    return v1[:, None] * v2[None, :]

def np_multiply_outer(v1, v2):
    return np.multiply.outer(v1, v2)

# Warmup all methods
warmup_v = np.array([1.0, 2.0, 3.0])
for func in [np_outer, np_einsum, np_broadcast, np_multiply_outer]:
    _ = func(warmup_v, warmup_v)

# Test sizes that might be in the evaluation
sizes = [5, 10, 50, 100, 500, 1000, 2000, 5000, 10000]
results = {}

for n in sizes:
    v1 = np.random.randn(n)
    v2 = np.random.randn(n)

    methods = {
        'np.outer': np_outer,
        'np.einsum': np_einsum,
        'np.broadcast': np_broadcast,
        'np.multiply.outer': np_multiply_outer
    }

    print(f'\nTesting size {n} (20 iterations):')
    method_times = {}

    for name, func in methods.items():
        times = []
        for _ in range(20):
            start = time.perf_counter()
            _ = func(v1, v2)
            times.append(time.perf_counter() - start)

        median_time = statistics.median(times) * 1000
        mean_time = statistics.mean(times) * 1000
        min_time = min(times) * 1000

        method_times[name] = {
            'median': median_time,
            'mean': mean_time,
            'min': min_time
        }

        print(f'  {name:20s}: median={median_time:8.3f}ms, mean={mean_time:8.3f}ms, min={min_time:8.3f}ms')

    # Find the fastest method based on median time
    fastest = min(method_times.items(), key=lambda x: x[1]['median'])
    print(f'  -> Winner: {fastest[0]} ({fastest[1]["median"]:.3f}ms)')
    results[n] = (fastest[0], method_times)

print('\n=== SUMMARY ===')
print('Recommended methods by size range:')
for n, (method, _) in sorted(results.items()):
    print(f'  n={n}: {method}')
EOF
